import torch
from torchvision import models, transforms
from PIL import Image
import io
import json
import base64
import requests

class ContentModerationAPI:
    def __init__(self):
        self.model = models.resnet50(pretrained=True)
        self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
        self.model.to(self.device)

    def predict(self, image_bytes):
        transform = transforms.Compose([
            transforms.Resize(256),
            transforms.CenterCrop(224),
            transforms.ToTensor(),
            transforms.Normalize(mean=[0.485, 0.456, 0.406], std=[0.229, 0.224, 0.225])
        ])
        
        image = Image.open(io.BytesIO(image_bytes))
        image = transform(image)
        image = image.unsqueeze(0).to(self.device)

        output = self.model(image)
        _, predicted_class_idx = torch.max(output, 1)
        confidence_score = torch.nn.functional.softmax(output, dim=1)[0][predicted_class_idx].item()

        return predicted_class_idx.item(), confidence_score

def main():
    api = ContentModerationAPI()
    
    image_bytes = request.get_json()['image']
    image_bytes = base64.b64decode(image_bytes)
    
    predicted_class, confidence_score = api.predict(image_bytes)

    response = {
        'predicted_class': predicted_class,
        'confidence_score': confidence_score
    }
    
    return json.dumps(response)

if __name__ == "__main__":
    from flask import Flask, request
    
    app = Flask(__name__)
    
    @app.route('/predict', methods=['POST'])
    def predict():
        response = main()
        return response

    app.run(debug=True)